        <button onClick={onScrollDown} className="inline-flex items-center gap-3 px-8 py-4 rounded-2xl text-xs md:text-sm font-black uppercase tracking-widest transition-all hover:scale-105 active:scale-95 shadow-2xl" style={{ backgroundColor: primary, color: '#fff' }}>
          Ver Colección
        </button>
      </div>
    </section>
  );
}

function ProbadorTrustBar({ brand }: { brand: BrandData }) {
  const rating = brand.rating ?? 4.9;
  const reviews = brand.total_reviews ?? 0;
  const items = [
    { value: rating.toFixed(1), label: 'rating' },
    { value: reviews > 0 ? `+${reviews}` : '96%', label: 'pruebas' },
    { value: '~12s', label: 'tiempo' },
    { value: 'IA', label: 'tech' },
  ];
  const bgColor = '#ffffff';
  const textColor = '#111111';
  const mutedColor = '#9ca3af';
  const borderColor = '#f3f4f6';
  
  return (
    <div className="flex border-b overflow-x-auto no-scrollbar" style={{ backgroundColor: bgColor, borderColor }}>
      {items.map((item, i) => (
        <div key={i} className="flex-1 min-w-[80px] flex flex-col items-center justify-center py-4 md:py-6 text-center border-r last:border-r-0" style={{ borderColor }}>
          <span className="text-sm md:text-xl font-black" style={{ color: textColor }}>{item.value}</span>
          <span className="text-[8px] md:text-[10px] mt-0.5 font-bold uppercase tracking-widest" style={{ color: mutedColor }}>{item.label}</span>
        </div>
      ))}
    </div>
  );
}

